		select sum(f007n) from `t_stock0003` 
 		where company_code = #{companycode,jdbcType=VARCHAR}
 		and f025v like  concat('%',#{type,jdbcType=VARCHAR},'%')



select sum(f017n) from `t_stock0004` t where t.company_code = #{companycode,jdbcType=VARCHAR}
and DATE(f001d) >= DATE(#{stime,jdbcType=TIMESTAMP}) 
and DATE_ADD(DATE(f001d),INTERVAL -2 DAY) <= DATE(#{etime,jdbcType=TIMESTAMP})



select f004n from t_company0011  where company_code = #{companycode,jdbcType=VARCHAR}
and DATE_ADD(DATE(f001d),INTERVAL -2 DAY) <= DATE(#{time,jdbcType=TIMESTAMP})
order by f001d desc limit 1
